var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 저 많은 사람들 앞에서 자기 소개라니 상상만 해도 끔찍하군.","JPN":"ハハ、あの大勢の前で自己紹介するなんて、想像しただけでゾッとするな。","ENG":"Haha, just nerve-racking to even imagine having to introduce myself in front of all those people.","TWN":"哈哈，竟然要在這麼多人面前自我介紹，光想就覺得可怕呢。"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"나처럼 외출하기 싫어하는 사람에겐 고역스러운 자리겠어.","JPN":"私のような外嫌いにはきつい状況だ。","ENG":"For someone who dislikes going outside like me, it seems awfully painful.","TWN":"對於像我這種不喜歡外出的人來說，應該是很痛苦的場合。"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하긴, 부담스러운 건 자네겠지만.","JPN":"ま、気が重いのは君の方なんだが。","ENG":"But, yeah. It’s you who is burdened, not me.","TWN":"不過，有壓力的人是你。"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 조금만 참게나, 친구.","JPN":"それでも少し辛抱してくれ。","ENG":"So, hang in there, friend.","TWN":"就再多忍耐一下吧，朋友。"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리에게는 이 세계가 앞으로 누구와 싸워야 하는지.","JPN":"我々には、これからこの世界が戦わねばならない相手について。","ENG":"Because we have a responsibility to tell how this world has fared thus far,","TWN":"因為我們有義務告訴大家，這個世界之後會需要對抗誰，"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"또 이 세계가 이제까지 어떻게 살아남았는지 알려 줘야 할 의무가 있으니까.","JPN":"それから、この世界が今までどうやって存続してきたのかについて、教える義務があるからな。","ENG":"as well as who it must fight next.","TWN":"以及這個世界是如何存活至今的。"},"stage":{"bg":"MS_1102","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"계산에 따르면 우리가 관리할 수 있는 한계는 여기까지라네.","JPN":"計算によると、我々が管理できるのはここまでだ。","ENG":"If my calculations are correct, this is the extent of our management.","TWN":"根據計算，我們能管理的權限僅止於此。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"결과적으로 잠들어 있던 신을 깨우는 데 성공한 셈이지.","JPN":"結果的には眠っていた神を目覚めさせることに成功したわけさ。","ENG":"After countless failed attempts and sacrifices we made.","TWN":"就結果而言，算是成功喚醒沉睡的神。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"수없이 많은 실패와, 수없이 많은 희생을 치른 끝에.","JPN":"数え切れないほど多くの失敗と犠牲の末に。","ENG":"We have finally succeeded in waking up the slumbering god.","TWN":"但這是經過無數的失敗和犧牲才帶來的結果。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"마침내 우리가 넘어서야 할 상대에게.","JPN":"やっと我々が乗り越えるべき相手に。","ENG":"And now facing the one whom we must overcome.","TWN":"我們終於抵達需要超越的對象"},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"탐미엘에게 다다른 걸세.","JPN":"タミエルにたどり着いたのだ。","ENG":"Tammiel.","TWN":"塔米爾的面前。"},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"최초의 세계 이후, 우리가 줄곧 이루고자 했던 계획대로.","JPN":"最初の世界の後、ずっと掲げてきた計画どおりにな。","ENG":"After the first world, we have achieved everything we planned.","TWN":"最初的世界之後，按著我們一直想達成的計畫。"},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 말 그대로, 여기까지라네.","JPN":"だが言葉どおり、ここまでさ。","ENG":"But literally, this is all.","TWN":"不過就如同我前面說的，僅止於此。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"우리의 계획도. 우리가 쌓아 왔던 모든 것도.","JPN":"我々の計画も、築いてきたすべても。","ENG":"Because nothing can be assumed or addressed from this point forward.","TWN":"我們的計畫，和我們至今所累積的一切，"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"이 시점 이후로는 상정하지 않았고, 상정할 수도 없었으니까.","JPN":"この時点より先は想定していなかったし、想定もできなかったんだ。","ENG":"Our plan, everything we have built... Nothing.","TWN":"從此之後，沒有計畫，也無法計畫。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"현존하는 테라브레인을 모두 동원해서 그 이후의 미래를 몇 번이고 계산하려 했네만.","JPN":"現存するテラブレインを総動員し、何度もその先の未来を計算しようとしたのだが。","ENG":"I have tried to calculate the future using all the Terrabrains known to exist, but...","TWN":"雖然動員過目前所有的特拉大腦，計算過幾次那之後的未來，"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"결과는 늘 같았어. 완벽한 미지수였지.","JPN":"結果は常に同じだった。完璧な未知数だ。","ENG":"The results were always the same. A perfect unknown.","TWN":"但結果都是一樣的，是完美的未知數。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"탐미엘이 다시 나타난 시기를 전후로 변수가 폭증하더군.","JPN":"タミエルが再び現れた時期を前後に、変数が爆増したのさ。","ENG":"Variables have been increasing exponentially ever since Tammiel appeared.","TWN":"塔米爾再次出現的時間點前後變數暴增。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 예측 불가능한 상황도 자네라면 무기로 활용할 수 있겠지.","JPN":"ま、予測不可能な状況も、君なら武器として活用できるだろう。","ENG":"But then again, you would somehow be using this unpredictable circumstance to your advantage.","TWN":"不過，你也可以將無法預測的情況，轉為你能運用的武器吧？"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"자네가 지금 서 있는 곳까지 도달하기 위해 사용했던 안배들은, 아주 오래 전부터 준비해 왔던 것들일세.","JPN":"君が今立っている時点までたどりつくために使ってきた人脈は、大昔から準備してきたものだ。","ENG":"The arrangements you have made to get to where you are now have been in the works for a long time.","TWN":"你之所以能夠抵達現在所處的位置，這些安排都是我很久以前便開始準備的。"},"stage":{"bg":"MS_1101","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그것들을 사용해서 거기까지 도달하는 데 성공한 <color=#ffd34c>나</color>는…","JPN":"だが、それらを使ってそこまでたどりつくことに成功した<color=#ffd34c>私</color>は……","ENG":"But the <color=#ffd34c>me</color> who has succeeded in reaching there is...","TWN":"不過能夠藉著這些安排，成功抵達目的地的<color=#ffd34c>我</color>…"},"stage":{"bg":"MS_1101","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"오직 자네뿐이야.","JPN":"君しかいなかった。","ENG":"You.","TWN":"就只有你。"},"stage":{"bg":"MS_1101","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"하늘 위의 신은 잡을 수도, 닿을 수도 없지만.","JPN":"天上の神は掴むことも、触れることもできない。","ENG":"Though gods in the sky are impossible to grasp nor reach...","TWN":"天上的神雖然捉不到也碰不到，"},"stage":{"bg":"MS_1101","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"겁없이 지상에 내려온 신이라면 얘기가 다르지.","JPN":"だが、地上に降り立った神なら話が違う。","ENG":"But a god fearless enough to descend... That is entirely another story.","TWN":"但若是降臨在地，則另當別論。"},"stage":{"bg":"MS_1101","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최초의 기록</color>은 관리국 본부에 안치시켜 두었어. 유용하게 써 주게나.","JPN":"<color=#ffd34c>最初の記録</color>は管理局の本部に保管されている。有効に使ってくれ。","ENG":"<color=#ffd34c>The first record</color> has been safely kept at the headquarters of the Administration. Please make good use of it.","TWN":"<color=#ffd34c>最原始的紀錄</color>就放置在管理局總部，請妥善利用。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 이제 작별이겠군.","JPN":"それでは、これでお別れだ。","ENG":"Well, then. I guess it is goodbye now.","TWN":"我話就說到這裡，"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"부디 자부심을 가지고, 우리가 다다르지 못했던 미지의 영역으로 나아가 주게.","JPN":"どうか誇りを持って、我々がたどり着けなかった未知の領域へ進んでくれたまえ。","ENG":"Please be proud and continue marching toward the unknown that we were unable to reach.","TWN":"最後，請你帶著信心，前往我們未曾到達的未知之境。"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"해결해야 할 의문은 단 하나.","JPN":"解決すべき疑問はただ一つだ。","ENG":"Only one question remains unanswered.","TWN":"而需要解決的問題只有一個，"},"stage":{"bg":"MAINSTREAM_000005","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>신을 쓰러뜨릴 수 있는가?</color>","JPN":"<color=#ffd34c>神を倒すことはできるのか？</color>","ENG":"<color=#ffd34c>Can you defeat a god?</color>","TWN":"<color=#ffd34c>能打倒神嗎？</color>"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};